To create a global error handler in Express, you write a middleware function that takes exactly 4 arguments: `(err, req, res, next)`. Express automatically recognizes this signature as an error handler.

You must place this middleware at the **very end** of your server file, after all your routes.

```javascript
const express = require('express');
const app = express();

// --- Your normal routes ---
app.get('/api/data', (req, res) => {
  throw new Error('Database connection failed!'); // Simulated crash
});

// --- Global Error Handler (Must be last) ---
app.use((err, req, res, next) => {
  console.error(`[Global Error Handler] ${err.message}`);

  res.status(500).json({
    success: false,
    error: 'Internal Server Error',
    message: err.message
  });
});

app.listen(3000, () => console.log('Server running on port 3000'));
```

Here is a standard AWS Lambda handler compatible with API Gateway Proxy Integrations. It correctly parses the body and returns the required `statusCode` and `body` string.

```javascript
exports.handler = async (event) => {
  try {
    // API Gateway passes the body as a JSON string
    const body = event.body ? JSON.parse(event.body) : {};
    const name = body.name || 'World';

    const responsePayload = {
      message: `Hello, ${name}!`,
      success: true
    };

    return {
      statusCode: 200,
      headers: {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*' // CORS requirement
      },
      body: JSON.stringify(responsePayload)
    };

  } catch (error) {
    console.error('Lambda Execution Error:', error);
    return {
      statusCode: 400,
      body: JSON.stringify({ error: 'Invalid JSON body provided' })
    };
  }
};
```
